import org.owasp.encoder.Encode;

import java.io.*;

public class XSSFixedCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = null;
        try {
            userInput = reader.readLine();
        } catch (IOException e) {
            e.printStackTrace();
        }

        // Properly encode user input before outputting it to the HTML response
        String encodedUserInput = Encode.forHtml(userInput);
        System.out.println("<p>Welcome, " + encodedUserInput + "!</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
